### JSON in Dart

JSON serialization converts Dart objects to JSON strings and vice versa using `dart:convert`.

```dart
import 'dart:convert';

void main() {
  // JSON encoding
  var data = {'name': 'Alice', 'age': 30};
  String jsonString = jsonEncode(data);
  print(jsonString); // {"name":"Alice","age":30}

  // JSON decoding
  Map<String, dynamic> decoded = jsonDecode(jsonString);
  print(decoded['name']); // Alice
}
```

### Manual Serialization

```dart
import 'dart:convert';

class User {
  final String name;
  final int age;
  final String? email;

  User({required this.name, required this.age, this.email});

  // To JSON
  Map<String, dynamic> toJson() => {
    'name': name,
    'age': age,
    'email': email,
  };

  // From JSON
  factory User.fromJson(Map<String, dynamic> json) {
    return User(
      name: json['name'] as String,
      age: json['age'] as int,
      email: json['email'] as String?,
    );
  }
}

void main() {
  var user = User(name: 'Alice', age: 30, email: 'alice@example.com');
  var jsonString = jsonEncode(user.toJson());

  var decoded = User.fromJson(jsonDecode(jsonString));
  print('${decoded.name} is ${decoded.age}');
}
```

### Nested Objects

```dart
class Address {
  final String street;
  final String city;

  Address(this.street, this.city);

  Map<String, dynamic> toJson() => {'street': street, 'city': city};
  factory Address.fromJson(Map<String, dynamic> json) =>
      Address(json['street'], json['city']);
}

class Person {
  final String name;
  final Address address;

  Person(this.name, this.address);

  Map<String, dynamic> toJson() => {
    'name': name,
    'address': address.toJson(),
  };

  factory Person.fromJson(Map<String, dynamic> json) => Person(
    json['name'],
    Address.fromJson(json['address']),
  );
}
```

### Lists of Objects

```dart
class Team {
  final String name;
  final List<User> members;

  Team(this.name, this.members);

  Map<String, dynamic> toJson() => {
    'name': name,
    'members': members.map((m) => m.toJson()).toList(),
  };

  factory Team.fromJson(Map<String, dynamic> json) => Team(
    json['name'],
    (json['members'] as List).map((m) => User.fromJson(m)).toList(),
  );
}
```

> **Key Point:** Always implement `toJson()` and `fromJson()` for serializable classes. Use `jsonEncode()` and `jsonDecode()` from `dart:convert`. In Flutter, consider using `json_serializable` package for automatic code generation.

