import 'dart:convert';

class Product {
  final int id;
  final String name;
  final double price;
  final List<String> tags;
  final bool inStock;

  Product({
    required this.id,
    required this.name,
    required this.price,
    this.tags = const [],
    this.inStock = true,
  });

  Map<String, dynamic> toJson() => {
    'id': id,
    'name': name,
    'price': price,
    'tags': tags,
    'inStock': inStock,
  };

  factory Product.fromJson(Map<String, dynamic> json) => Product(
    id: json['id'] as int,
    name: json['name'] as String,
    price: (json['price'] as num).toDouble(),
    tags: (json['tags'] as List?)?.cast<String>() ?? [],
    inStock: json['inStock'] as bool? ?? true,
  );
}

void main() {
  var jsonString = '{"id":1,"name":"Widget","price":9.99,"tags":["new","sale"],"inStock":true}';
  var product = Product.fromJson(jsonDecode(jsonString));
  print(product.name);
  print(jsonEncode(product.toJson()));
}
